// Define a sealed trait for allowed message types - no arbitrary deserialization
sealed trait SafeMessage
final case class TextMessage(sender: String, content: String) extends SafeMessage
final case class PingMessage(timestamp: Long) extends SafeMessage
final case class CommandMessage(command: String, args: List[String]) extends SafeMessage

// Actor that processes validated, safely-deserialized messages
class MessageProcessorActor extends Actor with ActorLogging {
  override def receive: Receive = {
    case TextMessage(sender, content) =>
      log.info(s"Received text from $sender: $content")

    case PingMessage(timestamp) =>
      log.info(s"Received ping at $timestamp")
      sender() ! PingMessage(System.currentTimeMillis())

    case CommandMessage(command, args) =>
      val allowedCommands = Set("status", "info", "list")
      if (allowedCommands.contains(command)) {
        log.info(s"Executing allowed command: $command with args: $args")
      } else {
        log.warning(s"Rejected disallowed command: $command")
      }

    case unknown =>
      log.warning(s"Received unknown message type, ignoring: ${unknown.getClass.getName}")
  }
}

// Safe JSON-based message deserializer with type whitelisting
class SafeMessageDeserializer {
  private val mapper: ObjectMapper = {
    val m = new ObjectMapper()
    m.registerModule(DefaultScalaModule)
    m
  }

  private val allowedTypes: Map[String, Class[_ <: SafeMessage]] = Map(
    "TextMessage" -> classOf[TextMessage],
    "PingMessage" -> classOf[PingMessage],
    "CommandMessage" -> classOf[CommandMessage]
  )

  def deserialize(json: String): Option[SafeMessage] = {
    try {
      val tree = mapper.readTree(json)
      val messageType = Option(tree.get("type")).map(_.asText()).getOrElse("")

