        val dataNode = tree.get("data")
        if (dataNode == null) {
          throw new IllegalArgumentException("Missing 'data' field")
        }
        mapper.treeToValue(dataNode, clazz)
      }
    } catch {
      case e: Exception =>
        println(s"Safe deserialization rejected input: ${e.getMessage}")
        None
    }
  }
}

// Network listener that accepts JSON messages over TCP (not raw Java serialization)
class SafeNetworkListener(actorSystem: ActorSystem, port: Int) {
  private val processor = actorSystem.actorOf(Props[MessageProcessorActor](), "messageProcessor")
  private val deserializer = new SafeMessageDeserializer()
  @volatile private var running = true

  def start(): Unit = {
    val serverSocket = new ServerSocket(port)
    println(s"Safe network listener started on port $port")

    new Thread(() => {
      while (running) {
        try {
          val clientSocket: Socket = serverSocket.accept()
          handleClient(clientSocket)
        } catch {
          case e: Exception =>
            if (running) println(s"Error accepting connection: ${e.getMessage}")
        }
      }
      serverSocket.close()
    }).start()
  }

  private def handleClient(socket: Socket): Unit = {
    new Thread(() => {
      try {
        val reader = new BufferedReader(new InputStreamReader(socket.getInputStream, "UTF-8"))
        val writer = new PrintWriter(socket.getOutputStream, true)

        var line = reader.readLine()
        while (line != null) {
          // Input size limit to prevent resource exhaustion
          if (line.length > 10000) {
            writer.println("""{"error": "Message too large"}""")
          } else {
            deserializer.deserialize(line) match {
              case Some(message) =>
                processor ! message
                writer.println("""{"status": "accepted"}""")
              case None =>
                writer.println("""{"error": "Invalid or disallowed message type"}""")
            }
          }
          line = reader.readLine()
        }
      } catch {
        case e: Exception =>
          println(s"Error handling client: ${e.getMessage}")
      } finally {
        socket.close()
      }
    }).start()
  }

  def stop(): Unit = {
    running = false
  }
}

